script.text:
      /* <flatten type="Javascript"> */
function active$EmployeePITInformationFilter(f) {f.add_onResponseComplete(on$EmployeePITInformationFilter$ResponseComplete);}
function close$EmployeePITInformationFilter(f) {try {f.remove_onResponseComplete(on$EmployeePITInformationFilter$ResponseComplete);} catch (ex) {}}
function on$EmployeePITInformationFilter$ResponseComplete(f, e) {
  var f = e.object, g = f.grid, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      g._refreshMemvars = true;
      g._dateFrom = f.getItemValue('ngay_tu');
      g._dateTo = f.getItemValue('ngay_den');
      g._dateHireFrom = f.getItemValue('ngay_vao_tu');
      g._dateHireTo = f.getItemValue('ngay_vao_den');
      g._staff = f.getItemValue('ma_nv');
      g._dept = f.getItemValue('ma_bp');
      g._pos = f.getItemValue('vi_tri');
      g._grade = f.getItemValue('ma_bac');
      g._official = f.getItemValue('official_yn');
      g._hiddenFields = [{Fields: 'tag', Value: !(g._official != '0')}];
      if (g._$k != null) g._$k = [];
      break;
    default:
      break;
  }
}
/* </flatten> */
